import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // === Simplest cases ===
  it.todo("empty item list → premium 5 G (only processing fee)");

  // === Single main item base premiums (+ processing fee) ===
  it.todo("single plain sword (no modifiers, 0 yrs, first contract) → 100 + 10 first + 5 fee = 115 G");
  it.todo("single plain amulet → 60 + 10 first + 5 fee = 75 G");
  it.todo("single plain staff → 80 + 10 first + 5 fee = 95 G");
  it.todo("single plain potion → 40 + 10 first + 5 fee = 55 G");

  // === Components ===
  it.todo("single rune → 25 + 10 first + 5 fee = 40 G");
  it.todo("single moonstone → 25 + 10 first + 5 fee = 40 G");

  // === Building block of 3 alike components ===
  it.todo("2 runes → 50 G base premium (no block)");
  it.todo("3 runes → 60 G base premium (block applies)");
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium (3+3+1 → no block since block is exactly 3? spec: 7 runes 175)");
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // === Item-specific modifiers ===
  it.todo("cursed sword adds 50% surcharge to the sword's base premium");
  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge applies (30%)");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 → both surcharges apply");

  // === Policy-wide modifiers ===
  it.todo("customer with exactly 2 years → loyalty discount (20%) applies");
  it.todo("customer with 1 year → no loyalty discount");
  it.todo("first ever insurance carries 10% initial assessment surcharge");
  it.todo("customer's second contract receives 15% follow-up discount");

  // === Rounding ===
  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");

  // === Integration examples ===
  it.todo("newcomer cursed sword (0 yrs, first contract, enchant 3) → premium 165 G");
  it.todo("long-standing customer's second cursed enchant-7 sword → premium 160 G");

  // === Modifier scope on multi-item policies ===
  it.todo("cursed sword + plain amulet (0 yrs, first contract) → cursed surcharge on sword only");

  // === Claim: basic reimbursement ===
  it.todo("regular sword (steel, enchant 3), damage 500 → payout 400 G (500 - 100 deductible)");
  it.todo("rune damage 200 → payout 100 G (200 - 100 deductible)");

  // === Claim: enchantment threshold ===
  it.todo("steel sword enchant 9, damage 1000 → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword enchant 9, damage 1000 → payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword enchant 5, damage 800 → payout 700 G (full then deductible)");
  it.todo("dragon-material sword enchant exactly 8, damage 1000 → payout 400 G");

  // === Claim: per-damage deductible ===
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per item)");

  // === Multiple items of same type ===
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("policy with two swords, dragon attack damages both → each is treated as separate damage");
  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero");

  // === Cap ===
  it.todo("policy with sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword: cap based on unmodified insurance value → cap 2000 G");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G");
  it.todo("sword cap 2000: first claim 1500 → payout 1400, remainingCap 600");
  it.todo("sword cap 2000: second claim 1500 → payout 600 (limited by remaining cap), remainingCap 0");

  // === Payout rounding ===
  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");

  // === Edge cases / error handling ===
  it.todo("quote with unknown item type → CLI exits non-zero, error on stderr, no results on stdout");
  it.todo("claim references damage for item not in policy → CLI exits non-zero, error on stderr");
  it.todo("claim damage entry with negative amount → CLI exits non-zero, error on stderr");
});

