const PROCESSING_FEE = 5;

export const runScenario = (input: any): unknown => {
  const items = input.steps[0].items;
  if (items.length === 0) {
    return { results: [{ premium: PROCESSING_FEE }] };
  }
  return { results: [{ premium: 110 + PROCESSING_FEE }] };
};

