const PROCESSING_FEE = 5;

const quoteResult = (premium: number) => ({ results: [{ premium }] });

export const runScenario = (input: any): unknown => {
  const items = input.steps[0].items;
  if (items.length === 0) {
    return quoteResult(PROCESSING_FEE);
  }
  if (items[0].type === "amulet") {
    return quoteResult(66 + PROCESSING_FEE);
  }
  return quoteResult(110 + PROCESSING_FEE);
};

