const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = { type: string };

const quoteResult = (premium: number) => ({ results: [{ premium }] });

const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];

const sum = (numbers: number[]): number =>
  numbers.reduce((total, n) => total + n, 0);

const applyFirstInsuranceSurcharge = (amount: number): number =>
  amount + amount * FIRST_INSURANCE_SURCHARGE_RATE;

const BLOCK_OF_THREE_BASE_PREMIUM = 60;

const isBlockOfThreeAlike = (items: Item[]): boolean =>
  items.length === 3 && items.every((item) => item.type === items[0].type);

const itemsBasePremium = (items: Item[]): number =>
  isBlockOfThreeAlike(items)
    ? BLOCK_OF_THREE_BASE_PREMIUM
    : sum(items.map(itemBasePremium));

const quotePremiumFor = (items: Item[]): number =>
  Math.ceil(applyFirstInsuranceSurcharge(itemsBasePremium(items)) + PROCESSING_FEE);

export const runScenario = (input: any): unknown => {
  const items: Item[] = input.steps[0].items;
  return quoteResult(quotePremiumFor(items));
};

