      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single plain amulet → 60 base + 6 first (10%) + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single plain staff → 80 base + 8 first (10%) + 5 fee = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff", material: "wood", enchantment: 2, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single plain potion → 40 base + 4 first (10%) + 5 fee = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion", material: "glass", enchantment: 1, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // === Components ===
  it("single rune → 25 base + 2.5 first (10%) + 5 fee = 32.5 → rounded up to 33 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });
  it("single moonstone → 25 base + 2.5 first (10%) + 5 fee = 33 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "moonstone" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });

  // === Building block of 3 alike components ===
  it("2 runes → 50 G base + 5 first (10%) + 5 fee = 60 G (no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes → 60 G base premium (block) + 6 first + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes → 100 G base + 10 first + 5 fee = 115 G (no block — block requires exactly 3)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes → 175 G base + 17.5 first + 5 fee = 197.5 → 198 G (no block; block requires exactly 3)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });
  it("2 runes + 1 moonstone → 75 G base + 7.5 first + 5 fee = 87.5 → 88 G (no block: different types)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones → 120 G base (2 blocks) + 12 first + 5 fee = 137 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // === Item-specific modifiers ===
  it("cursed sword (0 yrs, first contract) → 100 base + 50 curse + 10 first + 5 fee = 165 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }] }],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("sword enchantment exactly 5 → 100 base + 30 high-ench + 10 first + 5 fee = 145 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("sword with enchantment 4 → no high-enchantment surcharge → 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("cursed sword with enchantment 5 → 100 + 50 + 30 + 10 + 5 = 195 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }] }],
    });
    expect(result).toEqual({ results: [{ premium: 195 }] });
  });

  // === Policy-wide modifiers ===
  it("customer exactly 2 years (plain sword) → 100 + 10 first - 20 loyalty + 5 fee = 95 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it.todo("customer with 1 year → no loyalty discount");
  it.todo("first ever insurance carries 10% initial assessment surcharge");
  it.todo("customer's second contract receives 15% follow-up discount");

  // === Rounding ===
  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");

  // === Integration examples ===
  it.todo("newcomer cursed sword (0 yrs, first contract, enchant 3) → premium 165 G");
  it.todo("long-standing customer's second cursed enchant-7 sword → premium 160 G");

  // === Modifier scope on multi-item policies ===
  it.todo("cursed sword + plain amulet (0 yrs, first contract) → cursed surcharge on sword only");

  // === Claim: basic reimbursement ===
  it.todo("regular sword (steel, enchant 3), damage 500 → payout 400 G (500 - 100 deductible)");
  it.todo("rune damage 200 → payout 100 G (200 - 100 deductible)");

  // === Claim: enchantment threshold ===
  it.todo("steel sword enchant 9, damage 1000 → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword enchant 9, damage 1000 → payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword enchant 5, damage 800 → payout 700 G (full then deductible)");
  it.todo("dragon-material sword enchant exactly 8, damage 1000 → payout 400 G");

  // === Claim: per-damage deductible ===
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per item)");

  // === Multiple items of same type ===
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("policy with two swords, dragon attack damages both → each is treated as separate damage");
  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero");

  // === Cap ===
  it.todo("policy with sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword: cap based on unmodified insurance value → cap 2000 G");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G");
  it.todo("sword cap 2000: first claim 1500 → payout 1400, remainingCap 600");
  it.todo("sword cap 2000: second claim 1500 → payout 600 (limited by remaining cap), remainingCap 0");

  // === Payout rounding ===
  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");

  // === Edge cases / error handling ===
  it.todo("quote with unknown item type → CLI exits non-zero, error on stderr, no results on stdout");
  it.todo("claim references damage for item not in policy → CLI exits non-zero, error on stderr");
  it.todo("claim damage entry with negative amount → CLI exits non-zero, error on stderr");
});

